import { useLocation, useNavigate } from "react-router-dom";
import { useMemo, useState, useEffect } from "react";
import api from "../../api/axios";
import CustomerAppointmentForm from "./CustomerAppointmentForm";

export default function CustomerBookAppointment() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const [vehicleId, setVehicleId] = useState("");
  const [vehicles, setVehicles] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [availableSlots, setAvailableSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [minDate, setMinDate] = useState("");

  useEffect(() => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    setMinDate(tomorrow.toISOString().split("T")[0]);
  }, []);

  useEffect(() => {
    const loadVehicles = async () => {
      try {
        const res = await api.get("/vehicles");
        const available = res.data.filter((vehicle) => vehicle.status === "available");
        setVehicles(available);

        if (state?.vehicleId) {
          setVehicleId(state.vehicleId);
        } else if (available.length > 0) {
          setVehicleId(available[0]._id);
        }
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load vehicles");
      }
    };

    loadVehicles();
  }, [state]);

  useEffect(() => {
    const loadTimeSlots = async () => {
      if (!date) {
        setAvailableSlots([]);
        setTime("");
        return;
      }

      setLoading(true);
      setError("");
      setTime("");

      try {
        const res = await api.get(`/customer/appointments/available-slots/${date}`);
        const slots = res.data.slots || [];
        if (slots.length === 0) {
          setError("No available slots on this date. Please select another date.");
          setAvailableSlots([]);
        } else {
          setAvailableSlots(slots);
        }
      } catch (err) {
        const errorMsg = err.response?.data?.message || err.response?.data?.errors?.[0] || "Failed to load available slots";
        setError(errorMsg);
        setAvailableSlots([]);
      } finally {
        setLoading(false);
      }
    };

    loadTimeSlots();
  }, [date]);

  const selectedVehicle = useMemo(
    () => vehicles.find((vehicle) => vehicle._id === vehicleId),
    [vehicleId, vehicles]
  );

  const submit = async (event) => {
    event.preventDefault();
    if (!vehicleId) return alert("Please select a vehicle");
    if (!date) return alert("Please select a date");
    if (!time) return alert("Please select a time");

    try {
      await api.post("/customer/appointments/book", { vehicle: vehicleId, date, time });
      navigate("/my-appointments");
    } catch (err) {
      alert(err.response?.data?.message || "Booking failed");
    }
  };

  const vehicleField = (
    <div style={{ display: "grid", gap: "12px" }}>
      <div>
        <label className="label">Vehicle</label>
        <select value={vehicleId} onChange={(event) => setVehicleId(event.target.value)} className="select" required>
          {vehicles.length === 0 ? (
            <option value="">No available vehicles</option>
          ) : (
            vehicles.map((vehicle) => (
              <option key={vehicle._id} value={vehicle._id}>
                {vehicle.brand} {vehicle.model || vehicle.type || ""} ({vehicle.year})
              </option>
            ))
          )}
        </select>
      </div>
      {selectedVehicle ? (
        <div className="card cardPad" style={{ background: "rgba(255,255,255,0.86)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", gap: "12px", alignItems: "flex-start", flexWrap: "wrap" }}>
            <div>
              <div style={{ fontSize: "18px", fontWeight: 800, color: "var(--navy)" }}>
                {selectedVehicle.brand} {selectedVehicle.model || selectedVehicle.type || ""}
              </div>
              <div className="sub">{selectedVehicle.type || "Vehicle"} • {selectedVehicle.year || "Year not set"}</div>
            </div>
            <div style={{ fontSize: "18px", fontWeight: 800, color: "var(--primary)" }}>
              LKR {Number(selectedVehicle.price || 0).toLocaleString()}
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );

  return (
    <CustomerAppointmentForm
      title="Book Appointment"
      subtitle="Reserve a showroom visit or test drive with a cleaner premium booking experience."
      modeLabel="Customer Booking"
      vehicleField={vehicleField}
      date={date}
      setDate={setDate}
      minDate={minDate}
      availableSlots={availableSlots}
      loading={loading}
      error={error}
      time={time}
      setTime={setTime}
      submit={submit}
      submitLabel="Book Appointment"
      cancelLabel="Cancel"
      onCancel={() => navigate("/")}
      selectedVehicleLabel={
        selectedVehicle ? `${selectedVehicle.brand} ${selectedVehicle.model || selectedVehicle.type || ""}` : "Showroom visit"
      }
    />
  );
}
